#!/usr/bin/env python3
from __future__ import annotations
import argparse, datetime, html, json, re
from pathlib import Path
MARKER='GOALOS_AGIALPHA_PROOF_CARD_001_DEMAND_ENGINE_V31'
AGIALPHA='0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA'
SITE_URL='https://montrealai.github.io/goalos-agialpha-ascension/'
CONTRACT_FLOW=[
('GoalOSCommit','AEPGoalOSCommitRegistry.createCommit','Defines mission aim, constraints, authority, data boundary, rollback obligation.'),
('RunCommitment','AEPRunCommitmentRegistry.commitRun','Records plan graph, tools, context root, policy root, budget, latency.'),
('Sponsor mission','JobRegistry.postJob','Sponsor posts proof mission and escrows AGIALPHA reward.'),
('Builder claim','JobClaimBondManager.claimJob','Builder claims work with an AGIALPHA bond.'),
('Proof submission','ProofSubmissionRegistry.submitProof','Builder submits proof hash, proof URI, proof-card hash, proof bond.'),
('Reviewer bond','ReviewerBondRegistry.bondAsReviewer','Reviewer bonds AGIALPHA before validation.'),
('Review decision','ReviewerBondRegistry.reviewSubmission + ProofSubmissionRegistry.approveSubmission','Reviewer approves or rejects evidence.'),
('Proof Card','ProofCardRegistry.registerProofCard','Public-safe proof card is registered.'),
('Credential','ProofCredentialRegistry.issueCredential','Non-transferable credential is issued.'),
('Reputation','ReputationRegistry.recordApprovedProof','Builder and reviewer reputation update.'),
('Evidence Docket','AEPEvidenceDocketRegistry.registerEvidenceDocket','Claim, cost, risk and public/private boundary are anchored.'),
('Selection + Chronicle','AEPSelectionGate.issueSelectionCertificate + AEPChronicleRegistry.recordEntry','Only approved artifacts may shape future work.')]
def esc(x): return html.escape(str(x),quote=True)
def write(p,s): p=Path(p); p.parent.mkdir(parents=True,exist_ok=True); p.write_text(s,encoding='utf-8')
def shell(title,subtitle,body,canonical):
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>{esc(title)}</title><meta name="description" content="{esc(subtitle)}"><link rel="canonical" href="{esc(canonical)}"><style>:root{{--ink:#071426;--navy:#0b2451;--gold:#b8872f;--ivory:#fbf7ef;--line:#e6dccb;--muted:#5a6475}}*{{box-sizing:border-box}}body{{margin:0;background:linear-gradient(135deg,#fbf7ef,#efe3cf);color:var(--ink);font-family:Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,Arial,sans-serif;line-height:1.55}}a{{color:#0f5c9e}}.wrap{{max-width:1150px;margin:0 auto;padding:30px 22px}}.nav{{display:flex;justify-content:space-between;align-items:center;background:#071426;color:#fff;padding:14px 22px;position:sticky;top:0;z-index:10}}.nav a{{color:#fff;text-decoration:none;font-weight:800;margin-left:12px;font-size:14px}}.brand{{font-weight:900}}.hero{{border:1px solid var(--line);border-radius:30px;background:linear-gradient(135deg,#fff,#fff6df);box-shadow:0 22px 70px rgba(7,20,38,.12);padding:42px}}.kicker{{font-size:12px;font-weight:900;letter-spacing:.18em;text-transform:uppercase;color:var(--gold)}}h1{{font-size:clamp(40px,6vw,76px);line-height:.94;margin:12px 0 18px;letter-spacing:-.055em}}h2{{font-size:32px;letter-spacing:-.04em;margin:34px 0 12px}}h3{{font-size:20px;margin:18px 0 8px}}.lead{{font-size:20px;max-width:850px;color:#253447}}.grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(245px,1fr));gap:18px;margin-top:20px}}.card{{background:rgba(255,255,255,.9);border:1px solid var(--line);border-radius:22px;padding:20px;box-shadow:0 12px 32px rgba(7,20,38,.06)}}.feature{{border:2px solid var(--gold)!important;background:linear-gradient(135deg,#fff,#fff7e4)!important}}.metric{{font-size:38px;font-weight:900;color:var(--navy)}}.btn{{display:inline-flex;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:900;border:1px solid var(--navy);margin:4px}}.primary{{background:var(--navy);color:#fff}}.secondary{{background:#fff;color:var(--navy)}}table{{width:100%;border-collapse:collapse;background:#fff;border:1px solid var(--line);border-radius:16px;overflow:hidden}}th{{background:#071426;color:white;text-align:left;font-size:12px;text-transform:uppercase;letter-spacing:.08em}}td,th{{padding:12px;border-bottom:1px solid var(--line);vertical-align:top}}code{{background:#f3ead9;padding:2px 6px;border-radius:7px}}.panel{{border-left:6px solid var(--gold);background:#fff9ea;border-radius:18px;padding:18px;margin:18px 0}}.warning{{border-left-color:#8c1c13;background:#fff3f1}}.flow{{counter-reset:step}}.flow .card{{position:relative;padding-left:62px}}.flow .card:before{{counter-increment:step;content:counter(step);position:absolute;left:18px;top:18px;width:32px;height:32px;border-radius:50%;background:#071426;color:#fff;display:grid;place-items:center;font-weight:900}}.footer{{padding:40px 22px;color:#fff;background:#071426;margin-top:60px}}.small{{color:var(--muted);font-size:14px}}</style></head><body><nav class="nav"><div class="brand">GoalOS AGIALPHA Ascension</div><div><a href="index.html">Home</a><a href="usage-example.html">Usage</a><a href="proof-card-001.html">Proof Card</a><a href="smart-contract-flow.html">Contracts</a><a href="sovereign-rsi-loop.html">RSI</a></div></nav><main class="wrap">{body}</main><footer class="footer"><div class="wrap"><strong>The intelligence stays private. The proof becomes verifiable.</strong><p class="small" style="color:#cbd5e1">Public usage example. Not a live customer result, not financial advice, not legal/tax/security approval, and not mainnet deployment authorization.</p></div></footer></body></html>'''
def feature_panel():
    return f'''<!-- {MARKER}:home-feature:start --><section class="wrap"><div class="card feature"><div class="kicker">Proof Card 001</div><h2>One support workflow becomes verifiable trust.</h2><p class="lead">A buyer needs help. GoalOS improves the workflow. AGIALPHA coordinates proof work. A reviewer validates evidence. A Proof Card, credential, and reputation update make the improvement reusable.</p><a class="btn primary" href="proof-card-001.html">View Proof Card 001</a><a class="btn secondary" href="smart-contract-flow.html">See AGIALPHA contract flow</a><a class="btn secondary" href="sovereign-rsi-loop.html">See the RSI loop</a></div></section><!-- {MARKER}:home-feature:end -->'''
def contract_table():
    return '<table><thead><tr><th>Artifact</th><th>Contract / registry action</th><th>Role</th></tr></thead><tbody>'+''.join(f'<tr><td><strong>{esc(a)}</strong></td><td><code>{esc(c)}</code></td><td>{esc(p)}</td></tr>' for a,c,p in CONTRACT_FLOW)+'</tbody></table>'
def add_home_feature(site):
    p=site/'index.html'
    if not p.exists(): raise SystemExit('Missing site/index.html; refusing fallback.')
    text=p.read_text(encoding='utf-8',errors='replace')
    if MARKER in text:
        text=re.sub(r'<!-- '+MARKER+r':home-feature:start -->.*?<!-- '+MARKER+r':home-feature:end -->',feature_panel(),text,flags=re.S)
    elif '</body>' in text: text=text.replace('</body>',feature_panel()+'\n</body>')
    else: text+=feature_panel()
    p.write_text(text,encoding='utf-8')
def build_pages(site):
    receipt={'schema':'goalos.agialpha.proof_card_001.demand_engine.v3.1','id':'proof-card-001-buyer-rescue-workflow','generatedAt':datetime.datetime.utcnow().replace(microsecond=0).isoformat()+'Z','agialphaToken':AGIALPHA,'contractFlow':[{'artifact':a,'contractAction':c,'plainEnglish':p} for a,c,p in CONTRACT_FLOW],'rsiDefinition':'RSI is proof-backed upgrade rights: an artifact may shape future work only after evidence, evaluation, reviewer validation, scope control, challenge window, rollout, monitoring, and rollback readiness.','claimBoundary':'Illustrative public usage example; live Evidence Docket required for verified production claim.'}
    write(site/'data/usage-example-proof-card-001.json',json.dumps(receipt,indent=2))
    write(site/'evidence/proof-card-001-evidence-docket-template.json',json.dumps({'schema':'goalos.agialpha.evidence_docket.template.v3.1','status':'template-not-live-evidence','requiredEvidence':['GoalOSCommit hash','RunCommitment hash','JobRegistry job id','Claim bond event','ProofSubmission submission id','Reviewer attestation','ProofCard id','Credential id','Reputation update','Evidence Docket id','SelectionCertificate','Chronicle entry','Rollback target']},indent=2))
    write(site/'proof-card-001-share-card.svg','<svg xmlns="http://www.w3.org/2000/svg" width="1200" height="630"><rect width="1200" height="630" fill="#071426"/><rect x="60" y="60" width="1080" height="510" rx="36" fill="#fbf7ef"/><text x="100" y="150" fill="#b8872f" font-family="Arial" font-size="28" font-weight="900">PROOF CARD 001</text><text x="100" y="245" fill="#071426" font-family="Arial" font-size="76" font-weight="900">AI work becomes</text><text x="100" y="330" fill="#071426" font-family="Arial" font-size="76" font-weight="900">verifiable trust.</text><text x="100" y="430" fill="#334155" font-family="Arial" font-size="32">GoalOS improves the workflow. AGIALPHA coordinates proof work.</text></svg>')
    usage='<section class="hero"><div class="kicker">Usage example</div><h1>AI work becomes proof.</h1><p class="lead">A buyer needs support. GoalOS improves the workflow. AGIALPHA coordinates the proof mission. A reviewer validates evidence. A Proof Card makes the improvement understandable and reusable.</p><a class="btn primary" href="proof-card-001.html">Open Proof Card 001</a><a class="btn secondary" href="smart-contract-flow.html">See the smart contracts</a></section><section><h2>The loop</h2><div class="grid flow"><div class="card"><h3>Sponsor posts</h3><p>Support mission funded with AGIALPHA.</p></div><div class="card"><h3>Builder improves</h3><p>Workflow v1.0 becomes v1.1.</p></div><div class="card"><h3>Reviewer validates</h3><p>Evidence is checked against a rubric.</p></div><div class="card"><h3>Proof compounds</h3><p>Proof Card, credential, and reputation improve future routing.</p></div></div></section>'
    write(site/'usage-example.html',shell('Usage Example - Proof Card 001','A buyer support workflow becomes verifiable trust.',usage,SITE_URL+'usage-example.html'))
    proof='<section class="hero"><div class="kicker">Proof Card 001</div><h1>Buyer Rescue Workflow.</h1><p class="lead">A support workflow improves from v1.0 to v1.1. Private buyer data stays private. Public-safe proof becomes verifiable.</p></section><section><h2>Before / after</h2><table><thead><tr><th>Before</th><th>After</th><th>Why it matters</th></tr></thead><tbody><tr><td>Reply is polite but generic.</td><td>Reply classifies access issue, refund path, and escalation rule.</td><td>Buyer gets a clearer next step.</td></tr><tr><td>No reusable proof.</td><td>Evidence Docket + Proof Card created.</td><td>Future workflows can start smarter.</td></tr></tbody></table></section><section><h2>Claim boundary</h2><div class="panel warning">Illustrative public usage example. A live Evidence Docket is required before claiming a verified production outcome.</div></section>'
    write(site/'proof-card-001.html',shell('Proof Card 001 - Buyer Rescue Workflow','A support workflow becomes proof, credential, and reputation.',proof,SITE_URL+'proof-card-001.html'))
    contracts=f'<section class="hero"><div class="kicker">AGIALPHA contract flow</div><h1>Where AGIALPHA becomes useful.</h1><p class="lead">The buyer does not need crypto. AGIALPHA becomes useful when sponsors, builders, and reviewers need shared proof-work coordination.</p></section><section><h2>Contract and registry map</h2>{contract_table()}</section>'
    write(site/'smart-contract-flow.html',shell('Smart Contract Flow - AGIALPHA Proof Work','How AGIALPHA and the registries coordinate proof work.',contracts,SITE_URL+'smart-contract-flow.html'))
    rsi='<section class="hero"><div class="kicker">Sovereign RSI</div><h1>recursive self-improvement with proof.</h1><p class="lead">RSI is proof-backed upgrade rights. An improvement may shape future work only after it earns evidence, review, selection, monitoring, and rollback readiness.</p></section><section><h2>The RSI loop</h2><div class="grid flow"><div class="card"><h3>Observe</h3><p>Find weakness in v1.0.</p></div><div class="card"><h3>Improve</h3><p>Create v1.1.</p></div><div class="card"><h3>Prove</h3><p>Evidence Docket and ProofBundle.</p></div><div class="card"><h3>Select</h3><p>Reviewer and gate approval.</p></div><div class="card"><h3>Propagate</h3><p>Future routing improves.</p></div><div class="card"><h3>Rollback</h3><p>Unsafe changes reverse.</p></div></div></section>'
    write(site/'sovereign-rsi-loop.html',shell('Sovereign RSI Loop','The proof-backed upgrade cycle.',rsi,SITE_URL+'sovereign-rsi-loop.html'))
    season='<section class="hero"><div class="kicker">Season 001</div><h1>Five proof missions that create demand.</h1><p class="lead">Launch five useful proof missions that everyone can understand.</p></section><section><table><thead><tr><th>Mission</th><th>Proof output</th><th>Demand signal</th></tr></thead><tbody><tr><td>Customer Support Reply Workflow</td><td>Proof Card 001</td><td>Buyer trust</td></tr><tr><td>Claims-Safe Launch Content</td><td>Proof Card 002</td><td>Safe public growth</td></tr><tr><td>Workshop Application Qualification</td><td>Proof Card 003</td><td>Qualified pipeline</td></tr><tr><td>Sponsor Proof Job Creation</td><td>Proof Card 004</td><td>Sponsored missions</td></tr><tr><td>Builder / Reviewer Quality</td><td>Proof Card 005</td><td>Network quality</td></tr></tbody></table></section>'
    write(site/'season-001.html',shell('Season 001 Proof Missions','First five proof missions.',season,SITE_URL+'season-001.html'))
    share='<section class="hero"><div class="kicker">Share kit</div><h1>Proof is the growth loop.</h1><p class="lead">GoalOS turns AI work into proof: one support workflow improves, proof validates it, and reputation compounds it.</p></section><section><img src="proof-card-001-share-card.svg" style="max-width:100%;border-radius:24px;border:1px solid #e6dccb" alt="Proof Card 001 share card"></section>'
    write(site/'share.html',shell('Share Proof Card 001','Public share kit.',share,SITE_URL+'share.html'))
    sm=site/'sitemap.xml'; urls=['usage-example.html','proof-card-001.html','smart-contract-flow.html','sovereign-rsi-loop.html','season-001.html','share.html']; additions=''.join(f'<url><loc>{SITE_URL}{u}</loc></url>\n' for u in urls)
    if sm.exists():
        text=sm.read_text(encoding='utf-8',errors='replace')
        if 'proof-card-001.html' not in text: text=text.replace('</urlset>',additions+'</urlset>') if '</urlset>' in text else text+'\n'+additions
        sm.write_text(text,encoding='utf-8')
    else: write(sm,'<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">'+additions+'</urlset>')
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--site',default='site'); args=ap.parse_args(); site=Path(args.site)
    if not site.exists(): raise SystemExit('Site directory does not exist. Build existing site first; refusing fallback.')
    add_home_feature(site); build_pages(site); print(f'{MARKER}: added to {site}')
if __name__=='__main__': main()
